import{_ as t,W as d,X as e,a0 as i}from"./framework-174e6972.js";const l={},a=i('<p>Java提供了4种权限修饰符来修饰类以及类的内部结构，体现类及类的内部结构在被调用时可见性的大小。成员变量的4种作用域对比：</p><table><thead><tr><th>作用域与可见性</th><th>当前类</th><th>同包</th><th>父子类</th><th>其它包</th></tr></thead><tbody><tr><td>public</td><td>✔︎</td><td>✔︎</td><td>✔︎</td><td>✔︎</td></tr><tr><td>protected</td><td>✔︎</td><td>✔︎</td><td>✔︎</td><td></td></tr><tr><td>default</td><td>✔︎</td><td>✔︎</td><td></td><td></td></tr><tr><td>private</td><td>✔︎</td><td></td><td></td><td></td></tr></tbody></table><ol><li>public，表明该成员变量或方法对所有类或对象都是可见的，所有类或对象都可以直接访问。</li><li>protected，它的出现主要是为了子类能访问父类的成员变量或方法。</li><li>default（缺省）。表明该成员变量或方法只有自己和与其同一包内的类可见。</li><li>private，表明该成员变量或方法是私有的，只有当前类对其具有访问权限，除此之外的其他类或者对象都没有访问权限。</li></ol><div class="hint-container warning"><p class="hint-container-title">注意</p><ul><li>protected与default(缺省)最难区分，protected是为了子类能访问父类的成员变量或方法，因此多了父子类的访问权限。</li><li>这些修饰符不能用来修饰局部变量（方法内部定义的变量）。private和protected不能用来修饰类。(只有public、abstract或final能用来修饰类)；</li><li>由于Java支持嵌套类，如果一个类内部还定义了嵌套类，那么，嵌套类拥有访问<code>private</code>的权限；</li></ul></div>',4),r=[a];function c(o,n){return d(),e("div",null,r)}const h=t(l,[["render",c],["__file","12.Domain.html.vue"]]);export{h as default};
